#include <bits/stdc++.h>
using namespace std;

bool solve(int x, int y, int z) {
    // Check if z is greater than both jugs
    if(z > max(x, y)) return false;

    // Check if z is divisible by GCD of x and y
    // This is because we can only measure volumes that are multiples of GCD(x,y)
    if(z % __gcd(x, y) != 0) return false;

    return true;
}

int main() {
    int t;
    cin >> t;

    while(t--) {
        int x, y, z;
        cin >> x >> y >> z;

        if(solve(x, y, z)) 
            cout << "YES\n";
        else 
            cout << "NO\n";
    }
    return 0;
}
